    sections.push('')
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(renderModelInterface(model))
    sections.push('')
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(renderModelClient(model))
    sections.push('')
  }

  return sections.join('\n')
}

function lcFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

import type * as DMMF from '@prisma/dmmf'

/** Maps Prisma scalar type names to their TypeScript equivalents. */
const PRISMA_SCALAR_TO_TS: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/**
 * Converts a DMMF scalar or enum field type to its TypeScript representation,
 * accounting for list and optional modifiers.
 */
export function prismaFieldToTs(field: DMMF.Field): string {
  let baseType: string

  if (field.kind === 'enum') {
    baseType = field.type
  } else if (field.kind === 'scalar') {
    baseType = PRISMA_SCALAR_TO_TS[field.type] ?? 'unknown'
  } else {
    baseType = 'unknown'
  }

  const withList = field.isList ? baseType + '[]' : baseType
  return field.isRequired ? withList : withList + ' | null'
}

/** Renders a TypeScript `enum` declaration for a Prisma datamodel enum. */
export function renderEnum(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => '  ' + v.name + " = '" + v.name + "',").join('\n')
  return 'export enum ' + e.name + ' {\n' + values + '\n}'
}

/**
 * Renders a TypeScript `interface` for a Prisma model, including only scalar
 * and enum fields (relation fields are skipped to avoid circular references).
 */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind !== 'object')
  const lines = fields.map((f) => {
    const optionalMark = f.isRequired ? '' : '?'
    const tsType = prismaFieldToTs(f)
    return '  ' + f.name + optionalMark + ': ' + tsType
  })
  return 'export interface ' + model.name + ' {\n' + lines.join('\n') + '\n}'
}

/**
 * Renders a `const` object with typed CRUD methods (`findMany`, `findUnique`,
 * `create`, `update`, `delete`) for a given Prisma model. Each method accepts
 * a `baseUrl` and uses the global `fetch` API.
 */
export function renderModelClient(model: DMMF.Model): string {
  const name = model.name
  const resourcePath = lcFirst(name)

  const idField = model.fields.find((f) => f.isId)
  const idName = idField?.name ?? 'id'
  const idType = idField ? prismaFieldToTs(idField) : 'string'

  const lines: string[] = [
    'export const ' + resourcePath + 'Client = {',

    '  async findMany(baseUrl: string): Promise<' + name + '[]> {',
    "    const res = await fetch(`${baseUrl}/" + resourcePath + '`)',
    "    if (!res.ok) throw new Error(`GET /" + resourcePath + ' failed: ${res.statusText}`)',
    '    return res.json() as Promise<' + name + '[]>',
    '  },',
    '',

    '  async findUnique(baseUrl: string, ' + idName + ': ' + idType + '): Promise<' + name + ' | null> {',
    '    const res = await fetch(`${baseUrl}/' + resourcePath + '/${' + idName + '}`,)',
    // Note: the trailing comma above is intentional valid ES2017+ syntax
    '    if (res.status === 404) return null',
    "    if (!res.ok) throw new Error(`GET /" + resourcePath + '/${' + idName + '} failed: ${res.statusText}`)',
    '    return res.json() as Promise<' + name + '>',
    '  },',
    '',

    '  async create(baseUrl: string, data: Omit<' + name + ", '" + idName + "'>): Promise<" + name + '> {',
    '    const res = await fetch(`${baseUrl}/' + resourcePath + '`, {',
    "      method: 'POST',",
    "      headers: { 'Content-Type': 'application/json' },",
    '      body: JSON.stringify(data),',
    '    })',
    "    if (!res.ok) throw new Error(`POST /" + resourcePath + ' failed: ${res.statusText}`)',
    '    return res.json() as Promise<' + name + '>',
    '  },',
    '',

    '  async update(baseUrl: string, ' + idName + ': ' + idType + ', data: Partial<' + name + '>): Promise<' + name + '> {',
    '    const res = await fetch(`${baseUrl}/' + resourcePath + '/${' + idName + '}`, {',
    "      method: 'PATCH',",
    "      headers: { 'Content-Type': 'application/json' },",
    '      body: JSON.stringify(data),',
    '    })',
    "    if (!res.ok) throw new Error(`PATCH /" + resourcePath + '/${' + idName + '} failed: ${res.statusText}`)',
    '    return res.json() as Promise<' + name + '>',
    '  },',
    '',

    '  async delete(baseUrl: string, ' + idName + ': ' + idType + '): Promise<void> {',
    "    const res = await fetch(`${baseUrl}/" + resourcePath + '/${' + idName + '}`, { method: \'DELETE\' })',
    "    if (!res.ok) throw new Error(`DELETE /" + resourcePath + '/${' + idName + '} failed: ${res.statusText}`)',
    '  },',

    '}',
  ]

  return lines.join('\n')
}

/** Renders the complete `rest-client.ts` output from a DMMF document. */
export function renderRestClient(dmmf: DMMF.Document): string {
  const sections: string[] = ['// Auto-generated by @prisma/generator-rest-client. Do not edit.', '']

  for (const e of dmmf.datamodel.enums) {
    sections.push(renderEnum(e))
    sections.push('')
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(renderModelInterface(model))
    sections.push('')
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(renderModelClient(model))
    sections.push('')
  }

  return sections.join('\n')
}

function lcFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

